SELECT MAX(tide) AS highest_tide
FROM tide_data
WHERE sensor_id = 1;

SELECT sensor_id, COUNT(data_id) AS total_data_points
FROM tide_data
GROUP BY sensor_id;

SELECT MAX(maintenance_date)
FROM sensor_maintenance
WHERE sensor_id = 1;

SELECT DISTINCT sensor_id
FROM tide_data
WHERE date_time BETWEEN '2023-01-01' AND '2023-12-31';

SELECT date_time
FROM tide_data
ORDER BY date_time DESC;
